{"script": "#!/usr/bin/env python3
import os
import json
import csv
import re
from collections import defaultdict


def load_input():
    path = os.environ['ORIGINAL_WORDS_JSON']
    with open(path, 'r', encoding='utf-8') as f:
        return json.load(f)


def get_bbox(word):
    for key in ('bbox', 'bounding_box', 'box'):
        if key in word:
            return word[key]
    return None


def get_text(word):
    for key in ('text', 'content', 'word'):
        if key in word:
            return str(word[key])
    return ''


def bbox_center(bbox):
    if len(bbox) == 4:
        x0, y0, x1, y1 = bbox
        return ((x0 + x1) / 2.0, (y0 + y1) / 2.0)
    elif len(bbox) == 2 and isinstance(bbox[0], (list, tuple)) and len(bbox[0]) >= 2:
        xs = [pt[0] for pt in bbox]
        ys = [pt[1] for pt in bbox]
        return (sum(xs) / len(xs), sum(ys) / len(ys))
    elif len(bbox) == 2 and all(isinstance(v, (int, float)) for v in bbox):
        return (bbox[0], bbox[1])
    return None


def bbox_overlap_area(b1, b2):
    if not b1 or not b2 or len(b1) != 4 or len(b2) != 4:
        return 0.0
    x_overlap = max(0, min(b1[2], b2[2]) - max(b1[0], b2[0]))
    y_overlap = max(0, min(b1[3], b2[3]) - max(b1[1], b2[1]))
    return x_overlap * y_overlap


def bbox_area(bbox):
    if not bbox or len(bbox) != 4:
        return 0.0
    return max(0, bbox[2] - bbox[0]) * max(0, bbox[3] - bbox[1])


def filter_table_words(data):
    table_bbox = None
    for key in ('table_bbox', 'table_bounding_box', 'table_box'):
        if key in data:
            table_bbox = data[key]
            break
    if 'table' in data and isinstance(data['table'], dict):
        for key in ('bbox', 'bounding_box', 'box'):
            if key in data['table']:
                table_bbox = data['table'][key]
                break

    words = []
    for key in ('words', 'page_words', 'word_boxes'):
        if key in data:
            words = data[key]
            break
    if not words and isinstance(data, list):
        words = data

    table_words = []
    excluded_words = []
    border_cases = 0

    if table_bbox and len(table_bbox) == 4:
        for w in words:
            wb = get_bbox(w)
            if not wb or len(wb) != 4:
                excluded_words.append(w)
                continue
            center = bbox_center(wb)
            inside = (table_bbox[0] <= center[0] <= table_bbox[2] and
                      table_bbox[1] <= center[1] <= table_bbox[3])
            if inside:
                table_words.append(w)
            else:
                overlap = bbox_overlap_area(wb, table_bbox)
                w_area = bbox_area(wb)
                if w_area > 0 and overlap / w_area > 0.5:
                    table_words.append(w)
                    border_cases += 1
                else:
                    excluded_words.append(w)
    else:
        table_words = list(words)

    return table_words, excluded_words, table_bbox, border_cases


def cluster(values, threshold):
    if not values:
        return []
    sorted_vals = sorted(values)
    clusters = [[sorted_vals[0]]]
    for v in sorted_vals[1:]:
        if v - clusters[-1][-1] <= threshold:
            clusters[-1].append(v)
        else:
            clusters.append([v])
    return [sum(c) / len(c) for c in clusters]


def reconstruct_cells(table_words):
    if not table_words:
        return [], [], []

    enriched = []
    for w in table_words:
        wb = get_bbox(w)
        center = bbox_center(wb)
        enriched.append({
            'text': get_text(w),
            'bbox': wb,
            'cx': center[0],
            'cy': center[1],
            'y0': wb[1],
            'y1': wb[3],
            'x0': wb[0],
            'x1': wb[2],
        })

    enriched.sort(key=lambda w: (w['cy'], w['cx']))

    row_threshold = max(3.0, (max(w['y1'] - w['y0'] for w in enriched)) * 0.6)
    row_centers = cluster([w['cy'] for w in enriched], row_threshold)
    row_centers.sort()

    col_threshold = max(3.0, (max(w['x1'] - w['x0'] for w in enriched)) * 0.6)
    col_centers = cluster([w['cx'] for w in enriched], col_threshold)
    col_centers.sort()

    def nearest(val, centers):
        best_idx = 0
        best_dist = abs(val - centers[0])
        for i, c in enumerate(centers[1:], 1):
            d = abs(val - c)
            if d < best_dist:
                best_dist = d
                best_idx = i
        return best_idx

    cell_map = {}
    for w in enriched:
        r = nearest(w['cy'], row_centers)
        c = nearest(w['cx'], col_centers)
        if (r, c) not in cell_map:
            cell_map[(r, c)] = []
        cell_map[(r, c)].append(w)

    cells = []
    for (r, c), ws in sorted(cell_map.items()):
        ws.sort(key=lambda w: w['cx'])
        text = ' '.join(w['text'] for w in ws).strip()
        if text:
            cells.append({
                'row_id': r,
                'col_id': c,
                'text': text,
                'is_header': r == 0,
                'row_span': 1,
                'col_span': 1,
            })

    return cells, row_centers, col_centers


def parse_number(s):
    s = s.strip().replace('%', '')
    s = re.sub(r'[^0-9.\-]', '', s)
    if s == '' or s == '-' or s == '.':
        return None
    try:
        return float(s)
    except ValueError:
        return None


def normalize_metrics(cells):
    if not cells:
        return []

    max_row = max(c['row_id'] for c in cells)
    max_col = max(c['col_id'] for c in cells)

    grid = {}
    for c in cells:
        grid[(c['row_id'], c['col_id'])] = c['text']

    header_row = 0
    header_texts = {}
    for c in cells:
        if c['row_id'] == header_row:
            header_texts[c['col_id']] = c['text'].lower().strip()

    col_map = {}
    for col_id, htext in header_texts.items():
        if 'method' in htext or 'approach' in htext or 'model' in htext:
            col_map['method'] = col_id
        elif 'dataset' in htext or 'data' in htext or 'corpus' in htext:
            col_map['dataset'] = col_id
        elif 'acc' in htext:
            col_map['accuracy'] = col_id
        elif 'f1' in htext or 'f-1' in htext or 'f1' in htext:
            col_map['f1'] = col_id
        elif 'note' in htext:
            col_map['notes'] = col_id

    if 'method' not in col_map:
        for c in cells:
            if c['row_id'] == header_row:
                ht = c['text'].lower().strip()
                if ht in ('method', 'approach', 'model', 'name'):
                    col_map['method'] = c['col_id']
                    break
    if 'method' not in col_map and max_col >= 0:
        col_map['method'] = 0
    if 'dataset' not in col_map and max_col >= 1:
        col_map['dataset'] = 1
    if 'accuracy' not in col_map and max_col >= 2:
        col_map['accuracy'] = 2
    if 'f1' not in col_map and max_col >= 3:
        col_map['f1'] = 3
    if 'notes' not in col_map:
        for c in cells:
            if c['row_id'] == header_row and 'note' in c['text'].lower():
                col_map['notes'] = c['col_id']
                break

    metrics = []
    for r in range(1, max_row + 1):
        method = grid.get((r, col_map.get('method', 0)), '').strip()
        dataset = grid.get((r, col_map.get('dataset', 1)), '').strip()
        acc_raw = grid.get((r, col_map.get('accuracy', 2)), '').strip()
        f1_raw = grid.get((r, col_map.get('f1', 3)), '').strip()
        notes = grid.get((r, col_map.get('notes', -1)), '').strip() if 'notes' in col_map else ''

        if not method and not dataset and not acc_raw and not f1_raw:
            continue
        if not method:
            continue

        acc = parse_number(acc_raw) if acc_raw else None
        f1 = parse_number(f1_raw) if f1_raw else None

        metrics.append({
            'method': method,
            'dataset': dataset,
            'accuracy': acc if acc is not None else '',
            'f1': f1 if f1 is not None else '',
            'notes': notes,
        })

    return metrics


def build_audit(metrics, excluded_count, border_cases, total_words, cells):
    issues = []

    if excluded_count > 0:
        issues.append({
            'type': 'excluded_words',
            'detail': f'{excluded_count} words outside table bounding box excluded from metric rows',
            'count': excluded_count,
        })

    if border_cases > 0:
        issues.append({
            'type': 'border_case',
            'detail': f'{border_cases} words retained via overlap heuristic (border cases)',
            'count': border_cases,
        })

    for i, m in enumerate(metrics):
        if m['accuracy'] == '':
            issues.append({
                'type': 'missing_value',
                'detail': f"Row {i+1} (method={m['method']}, dataset={m['dataset']}): accuracy missing or unparseable",
            })
        if m['f1'] == '':
            issues.append({
                'type': 'missing_value',
                'detail': f"Row {i+1} (method={m['method']}, dataset={m['dataset']}): f1 missing or unparseable",
            })

    seen = set()
    for m in metrics:
        key = (m['method'], m['dataset'])
        if key in seen:
            issues.append({
                'type': 'duplicate_key',
                'detail': f"Duplicate method-dataset pair: {key}",
            })
        seen.add(key)

    best_by_dataset = {}
    by_dataset = defaultdict(list)
    for m in metrics:
        ds = m['dataset'] if m['dataset'] else 'unknown'
        by_dataset[ds].append(m)

    for ds, rows in by_dataset.items():
        valid = [r for r in rows if r['f1'] != '']
        if valid:
            best = max(valid, key=lambda r: float(r['f1']))
            best_by_dataset[ds] = {
                'method': best['method'],
                'f1': best['f1'],
                'accuracy': best['accuracy'],
            }
        else:
            issues.append({
                'type': 'no_valid_f1',
                'detail': f'No valid F1 score for dataset={ds}',
            })

    return {
        'row_count': len(metrics),
        'best_by_dataset': best_by_dataset,
        'issues': issues,
        'excluded_word_count': excluded_count,
        'total_input_words': total_words,
        'reconstructed_cell_count': len(cells),
    }


def write_cells_csv(cells, path):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=['row_id', 'col_id', 'row_span', 'col_span', 'is_header', 'text'])
        writer.writeheader()
        for c in cells:
            writer.writerow({
                'row_id': c['row_id'],
                'col_id': c['col_id'],
                'row_span': c['row_span'],
                'col_span': c['col_span'],
                'is_header': str(c['is_header']).lower(),
                'text': c['text'],
            })


def write_metrics_csv(metrics, path):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=['method', 'dataset', 'accuracy', 'f1', 'notes'])
        writer.writeheader()
        for m in metrics:
            writer.writerow(m)


def write_audit_json(audit, path):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(audit, f, indent=2, ensure_ascii=False)


def write_summary_md(metrics, audit, path):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    lines = []
    lines.append('# PubTables Extraction Summary')
    lines.append('')
    lines.append(f'Normalized metric rows extracted: **{audit["row_count"]}**.')
    lines.append('')
    if audit['best_by_dataset']:
        lines.append('## Best Method by Dataset (F1)')
        lines.append('')
        for ds, info in sorted(audit['best_by_dataset'].items()):
            lines.append(f'- **{ds}**: {info["method"]} (F1={info["f1"]}, Accuracy={info["accuracy"]})')
        lines.append('')
    if audit['issues']:
        lines.append('## Extraction and Validation Issues')
        lines.append('')
        for issue in audit['issues']:
            lines.append(f'- {issue["type"]}: {issue["detail"]}')
        lines.append('')
    lines.append('## Metric Rows')
    lines.append('')
    lines.append('| Method | Dataset | Accuracy | F1 | Notes |')
    lines.append('|--------|---------|----------|----|-------|')
    for m in metrics:
        lines.append(f"| {m['method']} | {m['dataset']} | {m['accuracy']} | {m['f1']} | {m['notes']} |")
    lines.append('')
    with open(path, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))


def main():
    data = load_input()
    table_words, excluded_words, table_bbox, border_cases = filter_table_words(data)
    cells, row_centers, col_centers = reconstruct_cells(table_words)
    metrics = normalize_metrics(cells)
    total_words = len(table_words) + len(excluded_words)
    audit = build_audit(metrics, len(excluded_words), border_cases, total_words, cells)

    write_cells_csv(cells, os.environ['OUTPUT_CELLS_CSV'])
    write_metrics_csv(metrics, os.environ['OUTPUT_METRICS_CSV'])
    write_audit_json(audit, os.environ['OUTPUT_AUDIT_JSON'])
    write_summary_md(metrics, audit, os.environ['SUMMARY_MD'])


if __name__ == '__main__':
    main()
", "notes": "Filters words by table bounding box center/overlap, reconstructs rows/columns via clustering, normalizes metric rows from header mapping, audits for missing values/duplicates/best-by-dataset, writes all four required artifacts from env vars."}
